Refactor this by extracting the discount calculation into its own function:

function priceFor(item, qty) {
  let total = item.price * qty;
  if (qty >= 10) total = total * 0.9;
  else if (qty >= 5) total = total * 0.95;
  return total;
}

Rename the variable `u` to `user` throughout this code:

function greet(u) {
  const name = u.name ?? 'friend';
  return 'Hello ' + name + ', id=' + u.id;
}

Inline the `taxRate` variable into its use:

function priceWithTax(amount) {
  const taxRate = 0.25;
  return amount + amount * taxRate;
}

Convert this Node.js callback code to async/await:

fs.readFile('./config.json', 'utf8', (err, data) => {
  if (err) return console.error(err);
  const cfg = JSON.parse(data);
  console.log(cfg);
});
